    31→static void emit(double x, double y)
    32→{
    33→#ifdef EN_PERF
    34→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    35→    volatile double vy = y;
    36→    g_acc += fmax(vx, vy);
    37→#else
    38→    double r = fmax(x, y);
    39→    printf("%016llx %016llx %016llx\n",
    40→           (unsigned long long)d2u(x),
    41→           (unsigned long long)d2u(y),
    42→           (unsigned long long)d2u(r));
    43→#endif
    44→}
    45→
    46→static void emit_u(uint64_t x_bits, uint64_t y_bits)
    47→{
    48→    emit(u2d(x_bits), u2d(y_bits));
    49→}
