    51→static void test_representative_100(void)
    52→{
    53→    /* --- Section 1: Special IEEE 754 values - NaN/Inf/zero combos (16) --- */
    54→    emit(0.0, 0.0);
    55→    emit(-0.0, 0.0);
    56→    emit(0.0, -0.0);
    57→    emit(-0.0, -0.0);
    58→    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    59→    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    60→    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -qNaN, 1.0 */
    61→    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    62→    emit_u(0x7ff8000000000000ULL, 0x7ff8000000000000ULL);  /* qNaN, qNaN */
    63→    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    64→    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf, 1.0 */
    65→    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);  /* 1.0, +Inf */
    66→    emit_u(0x3ff0000000000000ULL, 0xfff0000000000000ULL);  /* 1.0, -Inf */
    67→    emit_u(0x7ff0000000000000ULL, 0xfff0000000000000ULL);  /* +Inf, -Inf */
    68→    emit_u(0x7ff0000000000000ULL, 0x7ff0000000000000ULL);  /* +Inf, +Inf */
    69→    emit_u(0xfff0000000000000ULL, 0xfff0000000000000ULL);  /* -Inf, -Inf */
    70→
    71→    /* --- Section 2: Subnormal (denormal) values (10) --- */
    72→    emit_u(0x0000000000000001ULL, 0x0000000000000000ULL);  /* min positive subnormal, zero */
    73→    emit_u(0x8000000000000001ULL, 0x0000000000000000ULL);  /* min negative subnormal, zero */
    74→    emit_u(0x0000000000000001ULL, 0x8000000000000001ULL);  /* min pos subnorm, min neg subnorm */
    75→    emit_u(0x0008000000000000ULL, 0x0000000000000000ULL);  /* mid positive subnormal, zero */
    76→    emit_u(0x8008000000000000ULL, 0x0000000000000000ULL);  /* mid negative subnormal, zero */
    77→    emit_u(0x000fffffffffffffULL, 0x0000000000000000ULL);  /* max subnormal (just below DBL_MIN), zero */
    78→    emit_u(0x800fffffffffffffULL, 0x0000000000000000ULL);  /* max negative subnormal, zero */
    79→    emit_u(0x000fffffffffffffULL, 0x800fffffffffffffULL);  /* max pos subnorm, max neg subnorm */
    80→    emit_u(0x0008000000000000ULL, 0x8008000000000000ULL);  /* mid pos subnorm, mid neg subnorm */
    81→    emit_u(0x0000000000000001ULL, 0x000fffffffffffffULL);  /* min pos subnorm, max pos subnorm */
    82→
    83→    /* --- Section 3: Normal boundary values (8) --- */
    84→    emit(DBL_MIN, 0.0);                                    /* smallest normal, zero */
    85→    emit(-DBL_MIN, 0.0);                                   /* smallest negative normal, zero */
    86→    emit_u(0x0010000000000001ULL, 0x0010000000000000ULL);  /* one ULP above DBL_MIN, DBL_MIN */
    87→    emit(DBL_MIN, -DBL_MIN);                               /* smallest normal, negative counterpart */
    88→    emit(DBL_MAX, 1.0);                                    /* largest normal, one */
    89→    emit(-DBL_MAX, 1.0);                                   /* largest negative normal, one */
    90→    emit(DBL_MAX, -DBL_MAX);                               /* largest pos, largest neg */
    91→    emit_u(0x7fefffffffffffffULL, 0x7feeffffffffffffULL);  /* DBL_MAX, one ULP below DBL_MAX */
    92→
    93→    /* --- Section 4: Near 1.0 - ULP density region (10) --- */
    94→    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 1.0, 1.0 */
    95→    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 1.0, 1.0 */
    96→    emit_u(0x3ff0000000000000ULL, 0xbff0000000000000ULL);  /* 1.0, -1.0 */
    97→    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000001ULL);  /* one ULP below 1.0, one ULP above 1.0 */
    98→    emit_u(0xbfefffffffffffffULL, 0xbff0000000000000ULL);  /* one ULP toward zero from -1.0, -1.0 */
    99→    emit_u(0xbff0000000000001ULL, 0xbff0000000000000ULL);  /* one ULP away from zero from -1.0, -1.0 */
   100→    emit(1.0, 1.0);
   101→    emit(-1.0, -1.0);
   102→    emit_u(0x3ff0000000000010ULL, 0x3ff0000000000000ULL);  /* a few ULPs above 1.0, 1.0 */
   103→    emit_u(0x3feffffffffffff0ULL, 0x3ff0000000000000ULL);  /* a few ULPs below 1.0, 1.0 */
   104→
   105→    /* --- Section 5: Equal values (8) --- */
   106→    emit(0.5, 0.5);
   107→    emit(-0.5, -0.5);
   108→    emit(2.0, 2.0);
   109→    emit(-2.0, -2.0);
