   116→    emit(1.0, 2.0);
   117→    emit(2.0, 1.0);
   118→    emit(0.5, 1.5);
   119→    emit(1.5, 0.5);
   120→    emit(10.0, 20.0);
   121→    emit(20.0, 10.0);
   122→    emit(100.0, 50.0);
   123→    emit(50.0, 100.0);
   124→    emit(1.0e50, 1.0e100);
   125→    emit(1.0e100, 1.0e50);
   126→    emit(1.0e-10, 1.0e10);
