   142→    emit(-1.0, 1.0);
   143→    emit(1.0, -1.0);
   144→    emit(-2.0, 2.0);
   145→    emit(2.0, -2.0);
   146→    emit(-0.5, 0.5);
   147→    emit(0.5, -0.5);
   148→    emit(-1.0e100, 1.0e100);
