   151→    emit(1.0e-300, -1.0e-300);
   152→
   153→    /* --- Section 9: Large and extreme values (8) --- */
   154→    emit(1.0e300, 1.0e200);
   155→    emit(1.0e200, 1.0e300);
   156→    emit(-1.0e300, 1.0e300);
   157→    emit(1.0e300, -1.0e300);
   158→    emit(1.0e-300, 1.0e-200);
   159→    emit(1.0e-200, 1.0e-300);
   160→    emit(DBL_MAX, DBL_MIN);
   161→    emit(-DBL_MAX, DBL_MIN);
   162→
   163→    /* --- Section 10: Exponent sweep pairs (8) --- */
   164→    emit(1.0e-100, 1.0e-50);
   165→    emit(1.0e-50, 1.0e-10);
   166→    emit(1.0e-10, 1.0);
   167→    emit(1.0, 1.0e10);
   168→    emit(1.0e10, 1.0e50);
   169→    emit(1.0e50, 1.0e100);
   170→    emit(1.0e-100, 1.0e100);
   171→    emit(-1.0e-100, -1.0e100);
